import React, { useEffect, useState } from "react";
import { auth, Namedb, provider } from "../components/firebase_setup";
import { signInWithPopup } from "firebase/auth";
import { useNavigate } from "react-router-dom";
import { collection, getDocs, query, where } from "firebase/firestore";

function SignIn() {
    const [Value, setValue] = useState("");
    const navigate = useNavigate();

    const handleSignIn = () => {
        signInWithPopup(auth, provider).then(async (data) => {
            const u_email = data.user.email;
            setValue(u_email);
            localStorage.setItem("email", u_email);

            // Check if the user already has profile data in Firestore
            const Pcol = collection(Namedb, "ProfileData");
            const q = query(Pcol, where("u_email", "==", u_email));
            const Pdata = await getDocs(q);

            // If profile exists, skip Home and go directly to Feed
            if (!Pdata.empty) {
                navigate("/feed");
            } else {
                navigate("/home");
            }
        }).catch((error) => {
            console.error("Failed to Sign in", error);
        });
    }

    useEffect(() => {
        const storedEmail = localStorage.getItem("email");

        if (storedEmail) {
            // If a stored email exists, check if there's profile data
            const checkProfile = async () => {
                const Pcol = collection(Namedb, "ProfileData");
                const q = query(Pcol, where("u_email", "==", storedEmail));
                const Pdata = await getDocs(q);

                // If profile data exists, redirect to Feed, else sign in
                if (!Pdata.empty) {
                    navigate("/feed");
                } else {
                    navigate("/signIn");
                }
            };
            checkProfile();
        }
    }, [navigate]);

    return (
        <div>
            <h1>Welcome to Catsa. Please use your Google account to log in.</h1>
            {Value ? null : <button onClick={handleSignIn}>Sign In With Google</button>}
        </div>
    );
}

export default SignIn;
